464: RetryStateImpl::wouldRetryFromReset(const Http::StreamResetReason reset_reason,
465:                                     Http3Used http3_used, bool& disable_http3,
466:                                     bool upstream_request_started) {
467:   ASSERT(!disable_http3);
468:   // First check "never retry" conditions so we can short circuit (we never
469:   // retry if the reset reason is overflow).
470:   if (reset_reason == Http::StreamResetReason::Overflow) {
471:     return RetryDecision::NoRetry;
472:   }
473: 
474:   if (reset_reason == Http::StreamResetReason::LocalConnectionFailure ||
475:       reset_reason == Http::StreamResetReason::RemoteConnectionFailure ||
476:       reset_reason == Http::StreamResetReason::ConnectionTimeout) {
477:     if (http3_used != Http3Used::Unknown && clusterSupportsHttp3AndTcpFallback(cluster_)) {
478:       // Already got request encoder, so this must be a 0-RTT handshake failure. Retry
479:       // immediately.
480:       // TODO(danzh) consider making the retry configurable.
481:       ASSERT(http3_used == Http3Used::Yes,
482:              "0-RTT was attempted on non-Quic connection and failed.");
483:       return RetryDecision::RetryImmediately;
484:     }
485:     if (retry_on_ & RetryPolicy::RETRY_ON_CONNECT_FAILURE) {
486:       // This is a pool failure.
487:       return RetryDecision::RetryWithBackoff;
488:     }
489:   } else if (http3_used == Http3Used::Yes && clusterSupportsHttp3AndTcpFallback(cluster_) &&
490:              (retry_on_ & RetryPolicy::RETRY_ON_HTTP3_POST_CONNECT_FAILURE)) {
491:     // Retry any post-handshake failure immediately with http3 disabled if the
492:     // failed request was sent over Http/3.
493:     disable_http3 = true;
494:     return RetryDecision::RetryImmediately;
495:   }
496: 
497:   // Technically, this doesn't *have* to go before the RETRY_ON_RESET check,
498:   // but it's safer for the user if they have them both set
499:   // for some reason.
500:   if (retry_on_ & RetryPolicy::RETRY_ON_RESET_BEFORE_REQUEST && !upstream_request_started) {
501:     // Only return a positive retry decision if we haven't sent any bytes upstream.
502:     return RetryDecision::RetryWithBackoff;
503:   }
504: 
505:   if (retry_on_ & RetryPolicy::RETRY_ON_RESET) {
506:     return RetryDecision::RetryWithBackoff;
507:   }
508: 
509:   if (retry_on_ & (RetryPolicy::RETRY_ON_5XX | RetryPolicy::RETRY_ON_GATEWAY_ERROR)) {
510:     // Currently we count an upstream reset as a "5xx" (since it will result in
511:     // one). With RETRY_ON_RESET we may eventually remove these policies.
512:     return RetryDecision::RetryWithBackoff;
513:   }
514: 
515:   if ((retry_on_ & RetryPolicy::RETRY_ON_REFUSED_STREAM) &&
516:       reset_reason == Http::StreamResetReason::RemoteRefusedStreamReset) {
517:     return RetryDecision::RetryWithBackoff;
518:   }
519: 
520:   return RetryDecision::NoRetry;
521: }
